#include <stdio.h>
#include <stdlib.h>

// Define the structure for a binary tree node
typedef struct TreeNode {
    int val;
    struct TreeNode *left;
    struct TreeNode *right;
} TreeNode;

// Function to create a new binary tree node
TreeNode* createTreeNode(int val) {
    TreeNode* newNode = (TreeNode*) malloc(sizeof(TreeNode));
    if (!newNode) {
        printf("Memory error
");
        return NULL;
    }
    newNode->val = val;
    newNode->left = newNode->right = NULL;
    return newNode;
}

// Function to find nodes at distance k from the target node
void findNodesAtDistanceK(TreeNode* root, TreeNode* target, int k) {
    // Base case: if the tree is empty
    if (root == NULL) return;

    // If the current node is the target node
    if (root == target) {
        // Perform BFS to find nodes at distance k
        printf("%d ", root->val);
        return;
    }

    // Recursively search for the target node in the left and right subtrees
    findNodesAtDistanceK(root->left, target, k);
    findNodesAtDistanceK(root->right, target, k);
}

int main() {
    // Create the binary tree
    TreeNode* root = createTreeNode(3);
    root->left = createTreeNode(5);
    root->right = createTreeNode(1);
    root->left->left = createTreeNode(6);
    root->left->right = createTreeNode(2);
    root->left->right->left = createTreeNode(7);
    root->left->right->right = createTreeNode(4);
    root->right->left = createTreeNode(0);
    root->right->right = createTreeNode(8);

    // Set the target node and distance k
    TreeNode* target = root->left;
    int k = 2;

    // Find nodes at distance k from the target node
    findNodesAtDistanceK(root, target, k);

    return 0;
}

